agent_output:
{
  "domain_analysis": {
    "business_context": "Order cancellation is a critical lifecycle operation in logistics. It intersects fulfillment state, payment state, courier assignment, and customer trust. A cancellation that arrives too late in the fulfillment pipeline can cause real-world waste — a courier already en route, goods already picked, warehouse labor already spent. The business must define precise cut-off points where cancellation transitions from free to penalized to impossible.",
    "bounded_context": "Order Management / Order Lifecycle",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A customer's request to have goods picked up and/or delivered, with an associated lifecycle state." },
      { "term": "Cancellation", "definition": "A customer-initiated request to terminate an order before final delivery, triggering refund and fulfillment reversal processes." },
      { "term": "Cancellation Window", "definition": "The period or set of order states during which cancellation is permitted without penalty." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after resources have been committed (e.g., courier dispatched)." },
      { "term": "Order State", "definition": "The current phase of an order in its lifecycle (e.g., Placed, Confirmed, Assigned, Picked Up, In Transit, Out for Delivery, Delivered, Cancelled)." },
      { "term": "Fulfillment Reversal", "definition": "The operational process of unwinding committed resources — unassigning a courier, returning goods to origin, releasing inventory." },
      { "term": "Refund", "definition": "The return of payment to the customer, which may be full or partial depending on cancellation timing." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order may only be cancelled by the user who placed it (the sender/customer of record).",
      "invariant": true,
      "invariant_justification": "Allowing arbitrary users to cancel orders they don't own is a data integrity and authorization violation. This is a security invariant, not a policy choice.",
      "testable_assertion": "ASSERT that a cancellation request from user X for an order owned by user Y is rejected with an authorization error."
    },
    {
      "id": "BR-2",
      "rule": "An order in a terminal state (Delivered, Already Cancelled) cannot be cancelled.",
      "invariant": true,
      "invariant_justification": "A delivered order has completed its lifecycle — physical goods have changed hands. A cancelled order is already terminated. Allowing cancellation of terminal states would corrupt order state integrity.",
      "testable_assertion": "ASSERT that a cancellation request for an order with state=Delivered or state=Cancelled returns an error indicating the order is not cancellable."
    },
    {
      "id": "BR-3",
      "rule": "An order in state Placed or Confirmed (before courier assignment) may be cancelled with a full refund and no fee.",
      "invariant": false,
      "invariant_justification": "The refund amount and fee structure are business policy decisions that could be changed by leadership. The core invariant is BR-2 (terminal states block cancellation); the refund tier is a policy.",
      "testable_assertion": "ASSERT that cancelling an order in state=Placed or state=Confirmed results in refund_amount == original_payment_amount AND cancellation_fee == 0."
    },
    {
      "id": "BR-4",
      "rule": "An order in state Assigned or Picked Up (courier committed but not yet in transit to recipient) may be cancelled, subject to a cancellation fee.",
      "invariant": false,
      "invariant_justification": "Whether to allow cancellation at this stage and the fee amount are business policy. A VP could decide to waive fees or block cancellation entirely at this stage.",
      "testable_assertion": "ASSERT that cancelling an order in state=Assigned or state=PickedUp results in refund_amount == (original_payment_amount - cancellation_fee) AND cancellation_fee > 0."
    },
    {
      "id": "BR-5",
      "rule": "An order in state In Transit or Out for Delivery cannot be cancelled through self-service; it requires support intervention.",
      "invariant": false,
      "invariant_justification": "This is a policy decision balancing customer experience against operational waste. Some businesses allow late cancellation; others don't. A policy update could change this threshold.",
      "testable_assertion": "ASSERT that a self-service cancellation request for an order in state=InTransit or state=OutForDelivery is rejected with a message directing the user to contact support."
    },
    {
      "id": "BR-6",
      "rule": "When an order is cancelled, any assigned courier must be notified and unassigned.",
      "invariant": true,
      "invariant_justification": "If a courier is not unassigned, they will continue fulfilling a cancelled order — wasting resources and potentially delivering goods that should not be delivered. This is an operational integrity constraint.",
      "testable_assertion": "ASSERT that after successful cancellation of an order in state=Assigned, the courier assignment record is removed AND a notification event is emitted to the courier."
    },
    {
      "id": "BR-7",
      "rule": "Every cancellation must produce an immutable audit record capturing who cancelled, when, the order state at time of cancellation, and the refund/fee applied.",
      "invariant": true,
      "invariant_justification": "Audit trail is a data integrity requirement for financial reconciliation and dispute resolution. Without it, the system cannot prove what happened.",
      "testable_assertion": "ASSERT that after any successful cancellation, an audit record exists with fields: user_id, order_id, cancelled_at, order_state_at_cancellation, refund_amount, cancellation_fee."
    },
    {
      "id": "BR-8",
      "rule": "Cancellation is idempotent — cancelling an already-cancelled order returns success (not an error) with the original cancellation details.",
      "invariant": true,
      "invariant_justification": "In distributed systems, duplicate requests are inevitable. Returning an error for a retry of a successful cancellation would break client retry logic and create a poor user experience. Idempotency is a system integrity constraint.",
      "testable_assertion": "ASSERT that calling cancel twice on the same order returns HTTP 200 both times, with identical cancellation details, and does not create a duplicate audit record or duplicate refund."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A user has an order in state Placed",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to Cancelled, a full refund is initiated, no cancellation fee is charged, and an audit record is created."
    },
    {
      "id": "AC-2",
      "given": "A user has an order in state Confirmed",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to Cancelled, a full refund is initiated, no cancellation fee is charged, and an audit record is created."
    },
    {
      "id": "AC-3",
      "given": "A user has an order in state Assigned (courier assigned but has not picked up goods)",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to Cancelled, the courier is unassigned and notified, a partial refund (minus cancellation fee) is initiated, and an audit record is created."
    },
    {
      "id": "AC-4",
      "given": "A user has an order in state PickedUp (courier has goods but not yet in transit to recipient)",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to Cancelled, the courier is instructed to return goods to origin, a partial refund (minus cancellation fee) is initiated, and an audit record is created."
    },
    {
      "id": "AC-5",
      "given": "A user has an order in state InTransit",
      "when": "The user requests self-service cancellation",
      "then": "The request is rejected with a clear message: the order is too far in fulfillment for self-service cancellation, and the user is directed to contact support."
    },
    {
      "id": "AC-6",
      "given": "A user has an order in state Delivered",
      "when": "The user requests cancellation",
      "then": "The request is rejected with a clear message: delivered orders cannot be cancelled, and the user is directed to the returns/dispute process."
    },
    {
      "id": "AC-7",
      "given": "A user has an order that is already Cancelled",
      "when": "The user requests cancellation again (duplicate/retry)",
      "then": "The system returns success with the original cancellation details. No duplicate refund is issued. No duplicate audit record is created."
    },
    {
      "id": "AC-8",
      "given": "User A has an order",
      "when": "User B (a different user) requests cancellation of User A's order",
      "then": "The request is rejected with an authorization error. No state change occurs."
    },
    {
      "id": "AC-9",
      "given": "A user cancels an order in state Assigned",
      "when": "The cancellation is processed",
      "then": "The assigned courier receives a notification that the assignment has been revoked, and the courier's task queue is updated."
    },
    {
      "id": "AC-10",
      "given": "A cancellation request is submitted but the refund service is temporarily unavailable",
      "when": "The system processes the cancellation",
      "then": "The order transitions to Cancelled, the refund is queued for retry, and the user is informed that their refund is being processed. The cancellation is NOT rolled back due to a refund failure."
    }
  ],

  "edge_cases": [
    {
      "scenario": "Cancellation request arrives at the exact moment the order transitions from Confirmed to Assigned (race condition).",
      "expected_behavior": "The system must use optimistic locking or a state check at write time. If the state changed between read and write, the cancellation should be re-evaluated against the new state (Assigned), applying the appropriate fee — never silently applying the wrong refund tier."
    },
    {
      "scenario": "User cancels an order, then the payment provider reports the original charge failed (charge-back or decline after auth).",
      "expected_behavior": "The refund process must check whether the original charge was actually captured. If the charge was never captured, no refund is issued. The audit record should reflect 'no refund needed — charge not captured.'"
    },
    {
      "scenario": "A courier picks up goods and then the order is cancelled (state was Assigned at cancellation time but courier picked up between request and processing).",
      "expected_behavior": "Same race condition pattern as above. The system should evaluate the state at the moment of the atomic state transition, not at request time. If the courier already picked up, the PickedUp cancellation policy applies (return-to-origin flow)."
    },
    {
      "scenario": "Multiple rapid cancellation requests for the same order (e.g., user double-clicks the cancel button).",
      "expected_behavior": "Per BR-8, cancellation is idempotent. The first request succeeds and transitions the order. Subsequent requests return the same successful result. Exactly one refund is issued. Exactly one audit record is created."
    },
    {
      "scenario": "User cancels a multi-parcel order where one parcel is Assigned and another is already InTransit.",
      "expected_behavior": "This depends on whether partial cancellation is supported. If the system treats an order as atomic, the most restrictive parcel state governs — the user would be directed to support. If partial cancellation is supported, each parcel follows its own state rules. THIS IS AN AMBIGUITY — see escalations."
    },
    {
      "scenario": "Cancellation of an order with a promotional discount or coupon applied.",
      "expected_behavior": "The refund should reflect the actual amount charged, not the pre-discount price. Whether the coupon is returned to the user's account for reuse is a separate policy decision that must be defined."
    },
    {
      "scenario": "Cancellation during a scheduled maintenance window or system degradation.",
      "expected_behavior": "The cancellation request should either be processed fully or rejected cleanly. No partial state transitions (e.g., order marked Cancelled but refund never queued). Use transactional guarantees or saga compensation."
    },
    {
      "scenario": "User's account is suspended or flagged for fraud after placing the order but before cancelling.",
      "expected_behavior": "Fraud-flagged accounts should still be able to cancel (denying cancellation forces fulfillment of a potentially fraudulent order). However, the refund should be held pending fraud review rather than issued immediately."
    }
  ],

  "business_impact": {
    "financial": "Cancellation directly impacts revenue (refunds), courier compensation (wasted trips), and potential cancellation fee income. A poorly designed cancellation flow — either too restrictive (driving chargebacks and support costs) or too permissive (absorbing courier costs with no fee) — will erode margins. Getting the state-based fee tiers right is the primary financial lever.",
    "operational": "Every late-stage cancellation wastes courier time, fuel, and dispatch capacity. The courier notification system (BR-6) is critical — a delayed notification means a courier continues a dead delivery. The support team will also bear load from InTransit cancellation requests that can't be self-served.",
    "user": "Cancellation is a trust-building feature. Users who can't cancel feel trapped, leading to chargebacks and churn. Users who experience smooth cancellation are more likely to reorder. Clear communication about why a cancellation was denied (and what to do instead) is essential to user satisfaction.",
    "risk": "Primary risks: (1) Double-refund from race conditions or non-idempotent implementation — direct financial loss. (2) Courier not notified of cancellation — wasted delivery and potential wrong-person delivery. (3) Missing audit trail — inability to resolve disputes, regulatory exposure. (4) State race conditions — wrong refund tier applied.",
    "stakeholders_affected": [
      { "group": "Customers (senders)", "impact": "Gain ability to cancel orders; experience depends on clarity of cancellation rules and speed of refund." },
      { "group": "Couriers", "impact": "Must receive timely cancellation notifications to avoid wasted work. Late notifications erode courier trust and earnings." },
      { "group": "Customer Support", "impact": "Will handle InTransit and edge-case cancellations that can't be self-served. Need tooling and clear escalation paths." },
      { "group": "Finance / Accounting", "impact": "Must reconcile refunds, cancellation fees, and promotional credit returns. Audit trail is mandatory for reconciliation." },
      { "group": "Product / Growth", "impact": "Cancellation rate becomes a key metric. High cancellation rates may signal UX or pricing issues upstream." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec is a single sentence with no definition of order states, cancellation policies, fee structures, refund rules, or scope boundaries. I have applied standard logistics domain knowledge to infer reasonable rules, but nearly every business rule I defined (BR-3 through BR-5) is an assumption that needs PM/stakeholder validation. The multi-parcel question, coupon policy, and fraud-hold behavior are completely unspecified. Multiple ambiguities and missing context items are escalated below.",
    "high_confidence_areas": [
      "Terminal states (Delivered, already Cancelled) must block cancellation — this is universally true",
      "Authorization — only the order owner can cancel",
      "Idempotency requirement for cancellation",
      "Audit trail requirement",
      "Courier notification on cancellation is mandatory"
    ],
    "low_confidence_areas": [
      "Exact order states and which are cancellable vs not",
      "Cancellation fee amounts and tier boundaries",
      "Whether partial cancellation of multi-parcel orders is supported",
      "Coupon/promotion handling on cancellation",
      "Whether InTransit should be self-service cancellable or support-only",
      "Fraud-flagged account refund hold policy"
    ],
    "assumptions": [
      "The system has a well-defined order state machine with states like Placed, Confirmed, Assigned, PickedUp, InTransit, OutForDelivery, Delivered, Cancelled",
      "There is a payment/refund service that can process refunds asynchronously",
      "Couriers are assigned to individual orders and can be notified programmatically",
      "Cancellation fee tiers exist and are based on order state at time of cancellation",
      "Self-service cancellation is the scope — support-assisted cancellation is a separate flow"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order states allow cancellation, nor the refund/fee policy for each state. I have assumed a tiered model (free before assignment, fee after assignment, blocked after in-transit), but this is a critical business decision that must be explicitly confirmed.",
      "affected_stakeholders": ["Customers", "Finance", "Couriers", "Customer Support"],
      "options": [
        "A: Tiered model as I assumed — free before courier assignment, fee after, support-only once in transit",
        "B: Binary model — cancellable anytime before delivery, always free",
        "C: Time-based window — free within N minutes of order placement, fee or blocked after"
      ],
      "recommendation": "Option A (tiered by fulfillment state) is the industry standard for logistics. Recommend confirming with PM and Finance."
    },
    {
      "type": "ambiguity",
      "description": "Multi-parcel orders: if an order contains multiple parcels at different fulfillment stages, can the user cancel individual parcels, or is the order atomic? This fundamentally changes the data model and cancellation logic.",
      "affected_stakeholders": ["Customers", "Engineering", "Finance"],
      "options": [
        "A: Order is atomic — all parcels follow the most restrictive state",
        "B: Partial cancellation supported — each parcel independently cancellable"
      ],
      "recommendation": "Start with Option A (atomic) for simplicity unless multi-parcel is a known use case. Confirm with PM."
    },
    {
      "type": "missing_context",
      "description": "Cancellation fee amounts are undefined. Is it a flat fee, a percentage of order value, or variable by order state? This is a core financial parameter that cannot be assumed.",
      "affected_stakeholders": ["Finance", "Customers", "Product"],
      "options": [
        "A: Flat fee (e.g., $5)",
        "B: Percentage of order value (e.g., 10%)",
        "C: Variable by state (e.g., $3 for Assigned, $8 for PickedUp)"
      ],
      "recommendation": "Finance must define this. Engineering should implement it as a configurable policy, not a hardcoded value."
    },
    {
      "type": "missing_context",
      "description": "Coupon/promotion behavior on cancellation is unspecified. If a user used a one-time promo code and cancels, is the promo restored? This has direct revenue impact.",
      "affected_stakeholders": ["Marketing", "Finance", "Customers"],
      "options": [
        "A: Promo is restored to the user's account",
        "B: Promo is consumed — user loses it",
        "C: Depends on cancellation reason or timing"
      ],
      "recommendation": "Recommend Option A (restore promo) for customer goodwill, but this is a Marketing/Finance call."
    }
  ],

  "rejection_reasons": []
}

